// Get PDFs from Drive (Node 1 output)
const driveItems = $('1. Buscar PDFs en Drive').all();

// Parse Sheets API response (raw values format)
const sheetsData = $input.first().json;
const rows = sheetsData.values || [];
const headers = rows[0] || [];
const fileNameIdx = headers.indexOf('_fileName');

// Extract _fileName values from Sheets
const existingFileNames = new Set();
if (fileNameIdx >= 0) {
  for (let i = 1; i < rows.length; i++) {
    const val = (rows[i][fileNameIdx] || '').trim();
    if (val) existingFileNames.add(val);
  }
}

// Find new PDFs (in Drive but not in Sheets)
const newPdfs = driveItems.filter(item => {
  const fileName = (item.json.name || '').trim();
  return fileName && !existingFileNames.has(fileName);
});

if (newPdfs.length === 0) {
  return [{ json: { status: 'No hay PDFs nuevos', totalNew: 0, totalDrive: driveItems.length, totalSheets: rows.length - 1 } }];
}

return newPdfs.map(pdf => ({
  json: {
    fileId: pdf.json.id,
    fileName: pdf.json.name,
    webViewLink: pdf.json.webViewLink || '',
    isNew: true,
    totalNew: newPdfs.length,
    totalDrive: driveItems.length,
    totalSheets: rows.length - 1
  }
}));
